params.rule_content:
# Suricata rule for PowerShell encoded command execution (T1059)
alert http $HOME_NET any -> $EXTERNAL_NET any (
    msg:"ATT&CK T1059 PowerShell EncodedCommand Execution";
    flow:established,to_server;
    content:"-EncodedCommand"; nocase;
    classtype:attempted-user;
    sid:1000001; rev:1;
)
